import fs from 'fs';
import path from 'path';

const svgPath = 'public/favicon.svg';
const pngPath = 'public/favicon.png';

try {
    const svgContent = fs.readFileSync(svgPath, 'utf8');
    // Match the base64 string. It should be inside href="data:image/png;base64,..."
    const match = svgContent.match(/href="data:image\/png;base64,([^"]+)"/);

    if (match && match[1]) {
        const base64Data = match[1];
        const buffer = Buffer.from(base64Data, 'base64');
        fs.writeFileSync(pngPath, buffer);
        console.log(`Successfully extracted PNG to ${pngPath}`);
    } else {
        console.error('Could not find base64 PNG data in SVG');
    }
} catch (err) {
    console.error('Error:', err);
}

import { motion } from "framer-motion";

export function FadeInUp({ children, delay = 0, duration = 0.5, className = "" }) {
    return (
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true, margin: "-50px" }}
            transition={{ duration, delay, ease: "easeOut" }}
            className={className}
        >
            {children}
        </motion.div>
    );
}

import { useState } from "react"
import { motion, AnimatePresence } from "framer-motion"
import { Plus, Minus, ChevronDown } from "lucide-react"
import { useLanguage } from "../../lib/i18n"

const INITIAL_COUNT = 5

export function FAQ() {
    const { t } = useLanguage()
    const [showAll, setShowAll] = useState(false)

    const faqData = t('faq.items')
    const faqItems = Array.isArray(faqData) ? faqData : []
    const showMoreLabel = t('faq.show_more') || "Alle Fragen ansehen"
    const showLessLabel = t('faq.show_less') || "Weniger anzeigen"

    const visibleItems = showAll ? faqItems : faqItems.slice(0, INITIAL_COUNT)

    return (
        <section id="faq" className="py-32 bg-transparent relative">
            {/* Background Glow */}
            <div className="absolute bottom-0 right-0 w-[500px] h-[500px] bg-[var(--neon-purple)]/5 blur-[150px] pointer-events-none rounded-full translate-x-1/2 translate-y-1/2" />

            <div className="mx-auto max-w-4xl px-6 relative z-10">
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ duration: 0.5 }}
                    className="text-center mb-16 space-y-4"
                >
                    <h2 className="text-3xl font-bold text-white sm:text-5xl">{t('faq.title')}</h2>
                </motion.div>

                <div className="space-y-4">
                    {visibleItems.map((item, index) => (
                        <FAQItem key={index} question={item.q} answer={item.a} index={index} />
                    ))}
                </div>

                {/* Show more / less button */}
                {faqItems.length > INITIAL_COUNT && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        whileInView={{ opacity: 1 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.4, delay: 0.3 }}
                        className="text-center mt-10"
                    >
                        <button
                            onClick={() => setShowAll(!showAll)}
                            className="inline-flex items-center gap-2 px-6 py-3 rounded-full border border-white/10 bg-white/5 text-neutral-300 text-sm font-medium hover:bg-white/10 hover:border-[var(--neon-cyan)]/50 transition-all"
                        >
                            {showAll ? showLessLabel : showMoreLabel}
                            <ChevronDown className={`h-4 w-4 transition-transform ${showAll ? 'rotate-180' : ''}`} />
                        </button>
                    </motion.div>
                )}
            </div>
        </section>
    )
}

function FAQItem({ question, answer, index }) {
    const [isOpen, setIsOpen] = useState(false)

    return (
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.4, delay: index * 0.08 }}
            className="rounded-2xl border border-white/10 bg-white/5 overflow-hidden transition-colors hover:border-[var(--neon-blue)]/50 backdrop-blur-sm"
        >
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="flex w-full items-center justify-between p-6 text-left"
            >
                <span className="text-lg font-bold text-white">{question}</span>
                <div className="ml-4 shrink-0 rounded-full bg-white/10 p-2 text-white transition-colors hover:bg-[var(--neon-blue)]">
                    {isOpen ? <Minus className="h-4 w-4" /> : <Plus className="h-4 w-4" />}
                </div>
            </button>
            <AnimatePresence initial={false}>
                {isOpen && (
                    <motion.div
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: "auto", opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        transition={{ duration: 0.3, ease: "easeInOut" }}
                    >
                        <div className="px-6 pb-6 pt-0 text-neutral-400 leading-relaxed whitespace-pre-line">
                            {answer}
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </motion.div>
    )
}

