                filter: `blur(${size > 4 ? 1 : 0}px)`,
                boxShadow: `0 0 ${size * 2}px ${colorValue}`,
            }}
            initial={{ opacity: 0, scale: 0, y: 0 }}
            animate={{
                opacity: [0, 0.9, 0.7, 0.9, 0],
                scale: [0, 1, 1.3, 1, 0],
                y: [0, -150, -250, -350, -450],
