import { useMemo } from "react"
import { motion } from "framer-motion"

// Helper to generate random number between min and max
const random = (min, max) => Math.random() * (max - min) + min

const COLORS = ["cyan", "purple", "blue"]
const COLOR_MAP = {
    cyan: "rgba(0, 240, 255, 0.8)",
    purple: "rgba(176, 38, 255, 0.7)",
    blue: "rgba(47, 88, 255, 0.8)",
}

function Particle({ delay, duration, startX, startY, size, color }) {
    const colorValue = COLOR_MAP[color]

    return (
        <motion.div
            className="absolute rounded-full pointer-events-none"
            style={{
                width: size,
                height: size,
                left: `${startX}%`,
                top: `${startY}%`,
                background: colorValue,
                // Glow effect
                boxShadow: `0 0 ${size * 3}px ${colorValue}`,
                filter: `blur(${size > 4 ? 1 : 0}px)`,
            }}
            initial={{ opacity: 0.6, scale: 1, y: 0 }}
            animate={{
                opacity: [0.6, 0.9, 0.5, 0.9, 0.6],
                scale: [1, 1.2, 1, 1.3, 1],
                y: [0, -50, -100, -150, -200],
                x: [0, 10, -10, 5, 0],
            }}
            transition={{
                duration: duration,
                delay: delay * 0.3,
                repeat: Infinity,
                ease: "easeInOut",
            }}
        />
    )
}

export function BackgroundParticles() {
    // Generate 50 particles for a balanced effect without lag
    const particles = useMemo(() => {
        return Array.from({ length: 50 }).map((_, i) => ({
            id: i,
            startX: random(0, 100),
            startY: random(0, 100),
            size: random(2, 6),
            color: COLORS[Math.floor(random(0, COLORS.length))],
            delay: random(0, 10),
            duration: random(10, 20),
        }))
    }, [])

    return (
        <div className="fixed inset-0 z-5 pointer-events-none overflow-hidden">
            {particles.map((p) => (
                <Particle key={p.id} {...p} />
            ))}
        </div>
    )
}

