export function Navbar() {
    const [mobileMenuOpen, setMobileMenuOpen] = useState(false)
    const [isVisible, setIsVisible] = useState(true)
    const { language, switchLanguage, t } = useLanguage()
    const lastScrollY = useRef(0)
    const ticking = useRef(false)
    const location = useLocation()

    const navItems = [
        { label: t('nav.services'), href: routeMap.leistungen[language] },
        { label: t('nav.process'), href: routeMap.prozess[language] },
        { label: t('nav.about'), href: routeMap.ueberUns[language] },

        { label: t('nav.faq'), href: routeMap.faq[language] },
    ]

    useEffect(() => {
        const handleScroll = () => {
            if (!ticking.current) {
                window.requestAnimationFrame(() => {
                    const currentScrollY = window.scrollY
                    const isMobile = window.innerWidth < 768

                    if (isMobile) {
                        if (currentScrollY > lastScrollY.current && currentScrollY > 100) {
                            setIsVisible(false)
                        } else {
                            setIsVisible(true)
                        }
                    } else {
                        setIsVisible(true)
                    }

                    lastScrollY.current = currentScrollY
                    ticking.current = false
                })
                ticking.current = true
            }
        }

        window.addEventListener("scroll", handleScroll, { passive: true })
        return () => window.removeEventListener("scroll", handleScroll)
    }, [])

    useEffect(() => {
        if (!isVisible && mobileMenuOpen) {
            setMobileMenuOpen(false)
        }
    }, [isVisible, mobileMenuOpen])

    // Close mobile menu on route change
    useEffect(() => {
        setMobileMenuOpen(false)
    }, [location.pathname])

    return (
        <nav
            className={cn(
                "fixed top-2 left-0 right-0 z-50 mx-auto max-w-5xl rounded-full border border-white/10 bg-black/70 px-6 py-4 shadow-[0_0_20px_rgba(0,0,0,0.5)] backdrop-blur-xl",
