        >
            {/* Logo */}
            <Link to={routeMap.home[language]} className="flex items-center gap-3">
                <img
                    src="/BringsAI_Header.png"
                    alt="BringsAI"
                    className="h-14 w-auto"
                />
                <span
                    className="text-xl font-bold tracking-tight hidden sm:block text-white"
                    style={{
                        fontFamily: "'Outfit', 'Inter', system-ui, sans-serif",
                        letterSpacing: "-0.02em",
                    }}
                >
                    BringsAI
                </span>
            </Link>

            {/* Desktop Links */}
            <div className="hidden items-center gap-8 md:flex">
                {navItems.map((item) => (
                    <Link
                        key={item.label}
                        to={item.href}
                        className={cn(
                            "text-sm font-medium transition-all hover:text-white",
                            location.pathname.startsWith(item.href)
                                ? "text-white"
                                : "text-neutral-400"
                        )}
                    >
                        {item.label}
                    </Link>
                ))}

                {/* Language Switcher */}
                <div className="flex items-center bg-white/5 rounded-full p-1 border border-white/10">
                    <button
                        onClick={() => switchLanguage('de')}
                        className={cn(
                            "px-2 py-1 rounded-full text-lg leading-none transition-all",
                            language === 'de' ? "bg-white/10 shadow-sm opacity-100" : "opacity-50 hover:opacity-100"
                        )}
                        title="Deutsch"
                    >
                        🇩🇪
                    </button>
                    <button
                        onClick={() => switchLanguage('en')}
                        className={cn(
                            "px-2 py-1 rounded-full text-lg leading-none transition-all",
                            language === 'en' ? "bg-white/10 shadow-sm opacity-100" : "opacity-50 hover:opacity-100"
                        )}
                        title="English"
                    >
                        🇺🇸
                    </button>
                </div>
            </div>

            {/* CTA */}
            <div className="hidden md:block">
                <a href="https://cal.com/bringsai/erstgespraech" target="_blank" rel="noopener noreferrer">
                    <Button size="sm" className="rounded-full px-6 bg-white text-black hover:bg-neutral-200 shadow-[0_0_15px_rgba(255,255,255,0.3)] border-0">
                        {t('nav.cta')}
                    </Button>
                </a>
            </div>

            {/* Mobile Toggle */}
            <div className="md:hidden flex items-center gap-4">
