                        onClick={() => switchLanguage('en')}
                        className={cn(
                            "px-2 py-1 rounded-full text-sm leading-none transition-all",
                            language === 'en' ? "bg-white/10 shadow-sm opacity-100" : "opacity-50 hover:opacity-100"
                        )}
                    >
                        🇺🇸
